content.content:
  1→/**
  2→ * Email Pro for ZeroToShip
  3→ *
  4→ * Generates HTML emails from daily briefs for different subscriber tiers.
  5→ * Strategy: emails are teasers that drive users to the website for full briefs.
  6→ */
  7→
  8→import type { IdeaBrief } from '../generation/brief-generator';
  9→import logger from '../lib/logger';
 10→
 11→export type SubscriberTier = 'free' | 'pro';
 12→
 13→export const TIER_LIMITS: Record<SubscriberTier, number> = {
 14→  free: 3,
 15→  pro: 10,
 16→};
 17→
 18→const MAX_EMAIL_IDEAS = 10;
 19→const TAGLINE_TRUNCATE_LENGTH = 80;
 20→
 21→export interface EmailContent {
 22→  subject: string;
 23→  html: string;
 24→  text: string;
 25→}
 26→
 27→export interface EmailBuilderConfig {
 28→  baseUrl?: string;
 29→  unsubscribeUrl?: string;
 30→  upgradeUrl?: string;
 31→}
 32→
 33→const DEFAULT_CONFIG: Required<EmailBuilderConfig> = {
 34→  baseUrl: 'https://zerotoship.dev',
 35→  unsubscribeUrl: 'https://zerotoship.dev/unsubscribe',
 36→  upgradeUrl: 'https://zerotoship.dev/pricing',
 37→};
 38→
 39→const FONT_STACK = "'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif";
 40→
 41→function escapeHtml(text: string): string {
 42→  const htmlEscapes: Record<string, string> = {
 43→    '&': '&amp;',
 44→    '<': '&lt;',
 45→    '>': '&gt;',
 46→    '"': '&quot;',
 47→    "'": '&#39;',
 48→  };
 49→  return text.replace(/[&<>"']/g, char => htmlEscapes[char]);
 50→}
 51→
 52→function stripMarkdown(text: string): string {
 53→  return text
 54→    .replace(/\*\*(.+?)\*\*/g, '$1')
 55→    .replace(/\*(.+?)\*/g, '$1')
 56→    .replace(/`(.+?)`/g, '$1');
 57→}
 58→
 59→function truncateFeatureName(feature: string): string {
 60→  const delimiters = [' — ', ' - ', ': ', ' — '];
 61→  let name = feature;
 62→  for (const d of delimiters) {
 63→    const idx = name.indexOf(d);
 64→    if (idx > 0) {
 65→      name = name.slice(0, idx);
 66→      break;
 67→    }
 68→  }
 69→  return name.length > 60 ? name.slice(0, 57) + '...' : name;
 70→}
 71→
 72→const PLATFORM_LABELS: Record<string, string> = {
 73→  reddit: 'Reddit',
 74→  hn: 'Hacker News',
 75→  twitter: 'Twitter/X',
 76→  github: 'GitHub',
 77→};
 78→
 79→function formatScore(score: number | string): string {
 80→  return Number(score).toFixed(1);
 81→}
 82→
 83→function firstSentence(text: string): string {
 84→  const match = text.match(/^[^.!?]+[.!?]/);
 85→  return match ? match[0].trim() : text.slice(0, 150);
 86→}
 87→
 88→function getEffortBadgeStyle(effort: string): { bg: string; text: string } {
 89→  const lower = effort.toLowerCase();
 90→  if (lower === 'weekend') return { bg: '#ecfdf5', text: '#059669' };
 91→  if (lower === 'week') return { bg: '#fef3c7', text: '#d97706' };
 92→  return { bg: '#fee2e2', text: '#dc2626' };
 93→}
 94→
 95→function formatEffortLabel(effort: string): string {
 96→  const lower = effort.toLowerCase();
 97→  if (lower === 'weekend') return 'Weekend';
 98→  if (lower === 'week') return '1 Week';
 99→  if (lower === 'month') return '1 Month';
100→  if (lower === 'quarter') return 'Quarter+';
101→  return effort;
102→}
103→
104→function generateSubjectLine(topIdea: IdeaBrief, ideaCount: number): string {
105→  const name = topIdea.name.trim();
106→  const effort = formatEffortLabel(topIdea.effortEstimate).toLowerCase();
107→
108→  // Specific > generic. Lead with the product name or effort level so
109→  // the subject conveys value at a glance. Avoid revenue claims and questions.
110→  const templates = [
111→    `Today's #1: ${name} (${effort} build)`,
112→    `${name} — ${effort} build, ${formatScore(topIdea.priorityScore)}/100`,
113→    `${ideaCount} problems scored — ${name} leads`,
114→    `${name} tops today's ${ideaCount} problems`,
115→  ];
116→
117→  // Deterministic daily selection based on date
118→  const dateHash = new Date().toISOString().slice(0, 10).split('').reduce((a, c) => a + c.charCodeAt(0), 0);
119→  const subject = templates[dateHash % templates.length];
120→
121→  // Most inboxes truncate around ~50 chars. Target a tighter ceiling.
122→  return subject.length > 52 ? subject.slice(0, 49) + '...' : subject;
123→}
124→
125→function generatePreviewText(topIdea: IdeaBrief, ideaCount: number): string {
126→  return `${ideaCount} problems scored today. #1 is a ${formatEffortLabel(topIdea.effortEstimate).toLowerCase()} build.`;
127→}
128→
129→function buildPreheader(text: string): string {
130→  const spacer = '&#847;&zwnj;&nbsp;'.repeat(15);
131→  return `<span style="display:none;font-size:0;line-height:0;max-height:0;max-width:0;mso-hide:all;overflow:hidden;">${escapeHtml(text)}${spacer}</span>`;
132→}
133→
134→function buildHeader(dateStr: string): string {
135→  return `
136→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="border-bottom: 2px solid #6366f1;">
137→      <tr>
138→        <td style="padding: 16px 24px; font-family: ${FONT_STACK};">
139→          <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
140→            <tr>
141→              <td style="font-size: 20px; font-weight: 700; color: #111827;">ZeroToShip</td>
142→              <td style="text-align: right; font-size: 13px; color: #9ca3af;">${escapeHtml(dateStr)}</td>
143→            </tr>
144→          </table>
145→        </td>
146→      </tr>
147→    </table>`;
148→}
149→
150→function buildStatBar(ideaCount: number, topScore: string, platforms: string[]): string {
151→  const sourceLabel = platforms.length > 0
152→    ? `From <strong style="color: #111827;">${platforms.join(', ')}</strong>`
153→    : 'Curated daily';
154→
155→  return `
156→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #f9fafb;">
157→      <tr>
158→        <td style="padding: 12px 24px; font-family: ${FONT_STACK}; font-size: 13px; color: #6b7280; text-align: center;">
159→          <strong style="color: #111827;">${ideaCount}</strong> problems found &nbsp;&middot;&nbsp;
160→          ${sourceLabel} &nbsp;&middot;&nbsp;
161→          Top score: <strong style="color: #6366f1;">${topScore}</strong>
162→        </td>
163→      </tr>
164→    </table>`;
165→}
166→
167→function buildScoreChips(brief: IdeaBrief): string {
168→  const effortLabel = formatEffortLabel(brief.effortEstimate);
169→  return `
170→          <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin: 0 0 20px 0;">
171→            <tr>
172→              <td width="48%" style="background: #ffffff; padding: 10px 12px; border-radius: 8px; border: 1px solid #e5e7eb; text-align: center;">
173→                <div style="font-size: 10px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;">Priority</div>
174→                <div style="font-size: 18px; font-weight: 700; color: #6366f1; margin-top: 2px;">${formatScore(brief.priorityScore)}</div>
175→              </td>
176→              <td width="4%"></td>
177→              <td width="48%" style="background: #ffffff; padding: 10px 12px; border-radius: 8px; border: 1px solid #e5e7eb; text-align: center;">
178→                <div style="font-size: 10px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;">Build time</div>
179→                <div style="font-size: 18px; font-weight: 700; color: #111827; margin-top: 2px;">${escapeHtml(effortLabel)}</div>
180→              </td>
181→            </tr>
182→          </table>`;
183→}
184→
185→function buildSectionBlock(label: string, content: string): string {
186→  return `
187→          <div style="margin-bottom: 16px;">
188→            <div style="font-size: 11px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 6px;">${label}</div>
189→            <p style="margin: 0; font-size: 15px; color: #374151; line-height: 1.6;">${content}</p>
190→          </div>`;
191→}
192→
193→function buildHeroSection(brief: IdeaBrief, tier: SubscriberTier, config: Required<EmailBuilderConfig>): string {
194→  const ideaPath = `/idea/${brief.id || ''}`;
195→  // Email links are often opened in a logged-out browser session. For free users,
196→  // route through login with `next` so they land on a fully-unlocked brief after auth.
197→  const ideaUrl = tier === 'free'
198→    ? `${config.baseUrl}/login?next=${encodeURIComponent(ideaPath)}`
199→    : `${config.baseUrl}${ideaPath}`;
200→
201→  const ctaLabel = tier === 'pro' ? 'View full spec on dashboard' : 'Read the full spec';
202→
203→  const ctaHtml = `
204→          <table cellpadding="0" cellspacing="0" role="presentation" style="margin: 0 0 20px 0;">
205→            <tr>
206→              <td style="background-color: #6366f1; border-radius: 8px; mso-padding-alt: 0;">
207→                <a href="${escapeHtml(ideaUrl)}" style="display: inline-block; padding: 16px 32px; color: #ffffff; font-family: ${FONT_STACK}; font-size: 16px; font-weight: 600; text-decoration: none; border-radius: 8px;">${ctaLabel} &#8594;</a>
208→              </td>
209→            </tr>
210→          </table>`;
211→
212→  let bodyHtml: string;
213→
214→  if (tier === 'pro') {
215→    // Pro: full brief sections in the email, CTA at bottom
216→    const features = brief.keyFeatures.slice(0, 5);
217→    const featureListHtml = features.length > 0
218→      ? `
219→          <div style="margin-bottom: 16px;">
220→            <div style="font-size: 11px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 6px;">Key Features</div>
221→            ${features.map(f => `<div style="padding: 4px 0 4px 16px; font-size: 15px; color: #374151; line-height: 1.5; position: relative;"><span style="color: #059669; position: absolute; left: 0;">&#10003;</span> ${escapeHtml(stripMarkdown(f))}</div>`).join('\n            ')}
222→          </div>`
223→      : '';
224→
225→    const gtmHtml = brief.goToMarket
226→      ? buildSectionBlock('Go-to-Market', `${escapeHtml(stripMarkdown(brief.goToMarket.launchStrategy))}`)
227→      : '';
228→
229→    bodyHtml = `
230→          ${buildSectionBlock('The Problem', escapeHtml(stripMarkdown(brief.problemStatement)))}
231→          ${buildSectionBlock('Target Audience', escapeHtml(stripMarkdown(brief.targetAudience)))}
232→          ${buildSectionBlock('Proposed Solution', escapeHtml(stripMarkdown(brief.proposedSolution)))}
233→          ${featureListHtml}
234→          ${gtmHtml}
235→          ${ctaHtml}`;
236→  } else {
237→    // Free: CTA first (above the fold), then teaser hook below
238→    const hook = firstSentence(stripMarkdown(brief.problemStatement));
239→    const featureTeaser = brief.keyFeatures.length > 0
240→      ? ` The brief covers <strong>${escapeHtml(truncateFeatureName(stripMarkdown(brief.keyFeatures[0].toLowerCase())))}</strong>${brief.keyFeatures.length > 1 ? ` and ${brief.keyFeatures.length - 1} more approaches` : ''}.`
241→      : '';
242→
243→    bodyHtml = `
244→          ${ctaHtml}
245→          ${buildScoreChips(brief)}
246→          <p style="margin: 0; font-size: 15px; color: #6b7280; line-height: 1.6;">${escapeHtml(hook)}${featureTeaser}</p>`;
247→  }
248→
249→  return `
250→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
251→      <tr>
252→        <td style="padding: 24px; font-family: ${FONT_STACK}; background: linear-gradient(135deg, #eef2ff 0%, #faf5ff 100%); border-bottom: 1px solid #e5e7eb;">
253→          <span style="display: inline-block; background-color: #6366f1; color: #ffffff; padding: 4px 12px; border-radius: 16px; font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.5px;">Today's #1 Problem</span>
254→          <h2 style="margin: 12px 0 4px 0; font-size: 24px; font-weight: 700; color: #111827; line-height: 1.3;">${escapeHtml(brief.name)}</h2>
255→          <p style="margin: 0 0 16px 0; font-size: 16px; color: #6b7280; font-style: italic;">${escapeHtml(stripMarkdown(brief.tagline))}</p>
256→          ${tier === 'pro' ? buildScoreChips(brief) : ''}
257→          ${bodyHtml}
258→        </td>
259→      </tr>
260→    </table>`;
261→}
262→
263→function buildInlineUpgradeBanner(
264→  briefs: IdeaBrief[],
265→  config: Required<EmailBuilderConfig>
266→): string {
267→  const ideaCount = Math.min(briefs.length, MAX_EMAIL_IDEAS);
268→
269→  // Rotate copy based on day
270→  const dateHash = new Date().toISOString().slice(0, 10).split('').reduce((a, c) => a + c.charCodeAt(0), 0);
271→  const variants = [
272→    `You're seeing 1 of today's ${ideaCount} problems. Pro members get full specs for every one.`,
273→    `Today's lineup has ${ideaCount - 1} more problems just like this one.`,
274→    briefs.length >= 3
275→      ? `Today's #3 problem scored ${formatScore(briefs[2].priorityScore)} &#8212; and it's a ${formatEffortLabel(briefs[2].effortEstimate).toLowerCase()} build.`
276→      : `There are ${ideaCount - 1} more problems waiting for you today.`,
277→  ];
278→  const copy = variants[dateHash % variants.length];
279→
280→  return `
281→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
282→      <tr>
283→        <td style="padding: 0 24px;">
284→          <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #f5f3ff; border-left: 3px solid #6366f1; border-radius: 0 8px 8px 0;">
285→            <tr>
286→              <td style="padding: 14px 20px; font-family: ${FONT_STACK}; font-size: 14px; color: #374151; line-height: 1.5;">
287→                ${copy}
288→                <a href="${escapeHtml(config.upgradeUrl)}" style="color: #6366f1; font-weight: 600; text-decoration: none;"> Unlock all problems &#8594;</a>
289→              </td>
290→            </tr>
291→          </table>
292→        </td>
293→      </tr>
294→    </table>`;
295→}
296→
297→function buildIdeaCard(
298→  brief: IdeaBrief,
299→  rank: number,
300→  locked: boolean,
301→  tier: SubscriberTier,
302→  config: Required<EmailBuilderConfig>
303→): string {
304→  const effortStyle = getEffortBadgeStyle(brief.effortEstimate);
305→  const effortLabel = formatEffortLabel(brief.effortEstimate);
306→  const ideaPath = `/idea/${brief.id || ''}`;
307→  const ideaUrl = tier === 'free'
308→    ? `${config.baseUrl}/login?next=${encodeURIComponent(ideaPath)}`
309→    : `${config.baseUrl}${ideaPath}`;
310→  const tagline = brief.tagline.length > TAGLINE_TRUNCATE_LENGTH
311→    ? brief.tagline.slice(0, TAGLINE_TRUNCATE_LENGTH) + '...'
312→    : brief.tagline;
313→
314→  if (locked) {
315→    return `
316→      <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin-bottom: 8px;">
317→        <tr>
318→          <td style="background-color: #f9fafb; border-radius: 8px; border: 1px solid #e5e7eb; padding: 14px 16px; font-family: ${FONT_STACK}; opacity: 0.6;">
319→            <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
320→              <tr>
321→                <td width="28" style="vertical-align: top; font-size: 14px; font-weight: 700; color: #6366f1;">#${rank}</td>
322→                <td style="vertical-align: top; padding-left: 12px;">
323→                  <div style="font-size: 15px; font-weight: 600; color: #111827;">${escapeHtml(brief.name)}</div>
324→                  <div style="background-color: #d1d5db; border-radius: 4px; height: 12px; width: 70%; margin-top: 6px;"></div>
325→                </td>
326→                <td width="48" style="vertical-align: top; text-align: right;">
327→                  <span style="display: inline-block; background-color: #6366f1; color: #ffffff; padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 600;">PRO</span>
328→                </td>
329→              </tr>
330→            </table>
331→          </td>
332→        </tr>
333→      </table>`;
334→  }
335→
336→  return `
337→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin-bottom: 8px;">
338→      <tr>
339→        <td style="background-color: #f9fafb; border-radius: 8px; border: 1px solid #e5e7eb; padding: 14px 16px; font-family: ${FONT_STACK};">
340→          <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
341→            <tr>
342→              <td width="28" style="vertical-align: top; font-size: 14px; font-weight: 700; color: #6366f1;">#${rank}</td>
343→              <td style="vertical-align: top; padding-left: 12px;">
344→                <div style="font-size: 15px; font-weight: 600; color: #111827; margin-bottom: 2px;">${escapeHtml(brief.name)}</div>
345→                <div style="font-size: 13px; color: #6b7280; margin-bottom: 6px;">${escapeHtml(tagline)}</div>
346→                <span style="display: inline-block; background-color: ${effortStyle.bg}; color: ${effortStyle.text}; padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 600;">${escapeHtml(effortLabel)}</span>
347→              </td>
348→              <td width="48" style="vertical-align: top; text-align: right;">
349→                <div style="font-size: 18px; font-weight: 700; color: #6366f1;">${formatScore(brief.priorityScore)}</div>
350→              </td>
351→            </tr>
352→            <tr>
353→              <td></td>
354→              <td colspan="2" style="padding-top: 8px;">
355→                <a href="${escapeHtml(ideaUrl)}" style="color: #6366f1; font-size: 14px; font-weight: 600; text-decoration: none;">View problem &#8594;</a>
356→              </td>
357→            </tr>
358→          </table>
359→        </td>
360→      </tr>
361→    </table>`;
362→}
363→
364→function buildOtherIdeasSection(
365→  briefs: IdeaBrief[],
366→  tier: SubscriberTier,
367→  config: Required<EmailBuilderConfig>
368→): string {
369→  if (briefs.length <= 1) return '';
370→
371→  const limit = TIER_LIMITS[tier];
372→  const otherBriefs = briefs.slice(1, MAX_EMAIL_IDEAS);
373→  const lockedCount = Math.max(0, otherBriefs.length - (limit - 1));
374→  const maxLockedShown = 3;
375→  const weekendBuilds = otherBriefs
376→    .filter((b, i) => i + 2 > limit && b.effortEstimate.toLowerCase() === 'weekend')
377→    .length;
378→
379→  // Show unlocked cards + up to 3 locked cards (avoid paywall fatigue)
380→  const visibleBriefs = tier === 'free'
381→    ? otherBriefs.slice(0, (limit - 1) + maxLockedShown)
382→    : otherBriefs;
383→
384→  const rows = visibleBriefs.map((brief, index) => {
385→    const rank = index + 2;
386→    const locked = rank > limit;
387→    return buildIdeaCard(brief, rank, locked, tier, config);
388→  }).join('\n');
389→
390→  const lockedFooter = lockedCount > 0 && tier === 'free'
391→    ? `
392→      <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin-top: 8px;">
393→        <tr>
394→          <td style="text-align: center; padding: 12px 0; font-family: ${FONT_STACK};">
395→            <span style="font-size: 14px; color: #6b7280;">+${lockedCount} more problem${lockedCount > 1 ? 's' : ''} available with Pro${weekendBuilds > 0 ? ` &#8212; including ${weekendBuilds} weekend build${weekendBuilds > 1 ? 's' : ''}` : ''}</span>
396→          </td>
397→        </tr>
398→      </table>`
399→    : '';
400→
401→  return `
402→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
403→      <tr>
404→        <td style="padding: 24px; font-family: ${FONT_STACK};">
405→          <div style="font-size: 11px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 16px;">More Problems Today</div>
406→          ${rows}
407→          ${lockedFooter}
408→        </td>
409→      </tr>
410→    </table>`;
411→}
412→
413→function buildBottomCta(
414→  tier: SubscriberTier,
415→  freeCount: number,
416→  totalCount: number,
417→  config: Required<EmailBuilderConfig>
418→): string {
419→  if (tier === 'pro') return '';
420→
421→  return `
422→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #111827;">
423→      <tr>
424→        <td style="padding: 32px 24px; text-align: center; font-family: ${FONT_STACK};">
425→          <div style="font-size: 20px; font-weight: 700; color: #ffffff; margin-bottom: 8px;">You browsed ${freeCount} problems today. Pro members get full specs for all of them.</div>
426→          <div style="font-size: 16px; color: rgba(255,255,255,0.7); margin-bottom: 20px;">Every problem. Every spec. Every day.</div>
427→          <table cellpadding="0" cellspacing="0" role="presentation" style="margin: 0 auto;">
428→            <tr>
429→              <td style="background-color: #ffffff; border-radius: 8px;">
430→                <a href="${escapeHtml(config.upgradeUrl)}" style="display: inline-block; padding: 14px 32px; color: #111827; font-family: ${FONT_STACK}; font-size: 16px; font-weight: 600; text-decoration: none; border-radius: 8px;">Upgrade to Pro &#8594;</a>
431→              </td>
432→            </tr>
433→          </table>
434→        </td>
435→      </tr>
436→    </table>`;
437→}
438→
439→function buildFooter(config: Required<EmailBuilderConfig>): string {
440→  return `
441→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #f9fafb;">
442→      <tr>
443→        <td style="padding: 24px; text-align: center; font-family: ${FONT_STACK};">
444→          <p style="margin: 0 0 8px 0; font-size: 13px; color: #9ca3af;">You're receiving this because you signed up at zerotoship.dev.</p>
445→          <p style="margin: 0 0 8px 0; font-size: 13px;">
446→            <a href="${escapeHtml(config.baseUrl)}/settings" style="color: #6b7280; text-decoration: underline;">Manage preferences</a>
447→            &nbsp;&middot;&nbsp;
448→            <a href="${escapeHtml(config.unsubscribeUrl)}" style="color: #6b7280; text-decoration: underline;">Unsubscribe</a>
449→          </p>
450→          <p style="margin: 0; font-size: 12px; color: #9ca3af;">ZeroToShip ${new Date().getFullYear()}</p>
451→        </td>
452→      </tr>
453→    </table>`;
454→}
455→
456→export function buildDailyEmail(
457→  briefs: IdeaBrief[],
458→  tier: SubscriberTier,
459→  config: EmailBuilderConfig = {}
460→): EmailContent {
461→  const opts = { ...DEFAULT_CONFIG, ...config };
462→
463→  if (briefs.length === 0) {
464→    return {
465→      subject: 'ZeroToShip: No problems today',
466→      html: '<p>No new problems found today. Check back tomorrow!</p>',
467→      text: 'No new problems found today. Check back tomorrow!',
468→    };
469→  }
470→
471→  // Sort by priority score descending so the best idea is always #1
472→  briefs = [...briefs].sort((a, b) => Number(b.priorityScore) - Number(a.priorityScore));
473→
474→  const topIdea = briefs[0];
475→  const ideaCount = Math.min(briefs.length, MAX_EMAIL_IDEAS);
476→  const freeCount = Math.min(briefs.length, TIER_LIMITS.free);
477→  const dateStr = new Date().toLocaleDateString('en-US', {
478→    weekday: 'short',
479→    month: 'short',
480→    day: 'numeric',
481→  });
482→
483→  const subject = generateSubjectLine(topIdea, ideaCount);
484→  const previewText = generatePreviewText(topIdea, ideaCount);
485→
486→  // Extract unique platform names from all briefs' sources
487→  const platformSet = new Set<string>();
488→  for (const b of briefs) {
489→    if (b.sources) {
490→      for (const s of b.sources) {
491→        const label = PLATFORM_LABELS[s.platform];
492→        if (label) platformSet.add(label);
493→      }
494→    }
495→  }
496→  const platforms = [...platformSet];
497→
498→  const html = `<!DOCTYPE html>
499→<html lang="en">
500→<head>
501→  <meta charset="UTF-8">
502→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
503→  <meta name="color-scheme" content="light dark">
504→  <meta name="supported-color-schemes" content="light dark">
505→  <title>${escapeHtml(subject)}</title>
506→  <!--[if mso]>
507→  <style type="text/css">
508→    table { border-collapse: collapse; }
509→    td { font-family: Arial, sans-serif; }
510→  </style>
511→  <![endif]-->
512→</head>
513→<body style="margin: 0; padding: 0; background-color: #f5f5f5; font-family: ${FONT_STACK};">
514→  ${buildPreheader(previewText)}
515→  <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #f5f5f5;">
516→    <tr>
517→      <td align="center" style="padding: 16px 0;">
518→        <table width="600" cellpadding="0" cellspacing="0" role="presentation" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden;">
519→          <tr><td>
520→            ${buildHeader(dateStr)}
521→            ${buildStatBar(ideaCount, formatScore(topIdea.priorityScore), platforms)}
522→            ${buildHeroSection(topIdea, tier, opts)}
523→            ${tier === 'free' ? buildInlineUpgradeBanner(briefs, opts) : ''}
524→            ${buildOtherIdeasSection(briefs, tier, opts)}
525→            ${buildBottomCta(tier, freeCount, ideaCount, opts)}
526→            ${buildFooter(opts)}
527→          </td></tr>
528→        </table>
529→      </td>
530→    </tr>
531→  </table>
532→</body>
533→</html>`.trim();
534→
535→  const text = buildPlainTextEmail(briefs, tier, opts);
536→
537→  return { subject, html, text };
538→}
539→
540→function buildPlainTextEmail(
541→  briefs: IdeaBrief[],
542→  tier: SubscriberTier,
543→  config: Required<EmailBuilderConfig>
544→): string {
545→  if (briefs.length === 0) {
546→    return 'No new problems found today. Check back tomorrow!';
547→  }
548→
549→  const limit = TIER_LIMITS[tier];
550→  const topIdea = briefs[0];
551→  const ideaCount = Math.min(briefs.length, MAX_EMAIL_IDEAS);
552→  const dateStr = new Date().toLocaleDateString('en-US', {
553→    weekday: 'short',
554→    month: 'short',
555→    day: 'numeric',
556→  });
557→  const lines: string[] = [];
558→
559→  // Extract unique platform names for stat line
560→  const platformSet = new Set<string>();
561→  for (const b of briefs) {
562→    if (b.sources) {
563→      for (const s of b.sources) {
564→        const label = PLATFORM_LABELS[s.platform];
565→        if (label) platformSet.add(label);
566→      }
567→    }
568→  }
569→  const sourceLabel = platformSet.size > 0 ? `From ${[...platformSet].join(', ')}` : 'Curated daily';
570→
571→  lines.push(`ZEROTOSHIP | ${dateStr}`);
572→  lines.push(`${ideaCount} problems found | ${sourceLabel} | Top score: ${formatScore(topIdea.priorityScore)}`);
573→  lines.push('='.repeat(60));
574→  lines.push('');
575→
576→  lines.push("#1 TODAY'S TOP PROBLEM");
577→  lines.push('');
578→  lines.push(topIdea.name);
579→  lines.push(`"${stripMarkdown(topIdea.tagline)}"`);
580→  lines.push('');
581→  lines.push(`Read the full spec: ${config.baseUrl}/idea/${topIdea.id || ''}`);
582→  lines.push('');
583→  lines.push(`Score: ${formatScore(topIdea.priorityScore)}/100 | Build time: ${formatEffortLabel(topIdea.effortEstimate)}`);
584→  lines.push('');
585→
586→  if (tier === 'pro') {
587→    lines.push('THE PROBLEM');
588→    lines.push(stripMarkdown(topIdea.problemStatement));
589→    lines.push('');
590→    lines.push('TARGET AUDIENCE');
591→    lines.push(stripMarkdown(topIdea.targetAudience));
592→    lines.push('');
593→    lines.push('PROPOSED SOLUTION');
594→    lines.push(stripMarkdown(topIdea.proposedSolution));
595→    lines.push('');
596→    if (topIdea.keyFeatures.length > 0) {
597→      lines.push('KEY FEATURES');
598→      topIdea.keyFeatures.slice(0, 5).forEach(f => lines.push(`  ✓ ${stripMarkdown(f)}`));
599→      lines.push('');
600→    }
601→    if (topIdea.goToMarket) {
602→      lines.push('GO-TO-MARKET');
603→      lines.push(stripMarkdown(topIdea.goToMarket.launchStrategy));
604→      lines.push('');
605→    }
606→    lines.push(`View full spec on dashboard: ${config.baseUrl}/idea/${topIdea.id || ''}`);
607→  } else {
608→    lines.push(firstSentence(stripMarkdown(topIdea.problemStatement)));
609→    if (topIdea.keyFeatures.length > 0) {
610→      lines.push(`The brief covers ${truncateFeatureName(stripMarkdown(topIdea.keyFeatures[0].toLowerCase()))}${topIdea.keyFeatures.length > 1 ? ` and ${topIdea.keyFeatures.length - 1} more approaches` : ''}.`);
611→    }
612→    lines.push('');
613→    lines.push(`Read the full spec: ${config.baseUrl}/idea/${topIdea.id || ''}`);
614→  }
615→  lines.push('');
616→  lines.push('-'.repeat(60));
617→  lines.push('');
618→
619→  if (briefs.length > 1) {
620→    lines.push("MORE PROBLEMS TODAY");
621→    lines.push('');
622→
623→    briefs.slice(1, MAX_EMAIL_IDEAS).forEach((brief, index) => {
624→      const rank = index + 2;
625→      const locked = rank > limit;
626→
627→      if (locked) {
628→        lines.push(`#${rank} ${brief.name} [PRO]`);
629→      } else {
630→        lines.push(`#${rank} ${brief.name} — Score: ${formatScore(brief.priorityScore)} [${formatEffortLabel(brief.effortEstimate)}]`);
631→        lines.push(`   "${brief.tagline}"`);
632→        lines.push(`   View problem: ${config.baseUrl}/idea/${brief.id || ''}`);
633→      }
634→      lines.push('');
635→    });
636→  }
637→
638→  if (tier === 'free') {
639→    const lockedCount = Math.max(0, Math.min(briefs.length, MAX_EMAIL_IDEAS) - TIER_LIMITS.free);
640→    if (lockedCount > 0) {
641→      lines.push('-'.repeat(60));
642→      lines.push(`+${lockedCount} more problems with full specs available on Pro.`);
643→      lines.push(`Unlock all problems: ${config.upgradeUrl}`);
644→      lines.push('');
645→    }
646→
647→    lines.push('-'.repeat(60));
648→    lines.push(`You browsed ${Math.min(briefs.length, TIER_LIMITS.free)} problems today. Pro members get full specs for all of them.`);
649→    lines.push('Every problem. Every spec. Every day.');
650→    lines.push(`Upgrade to Pro: ${config.upgradeUrl}`);
651→    lines.push('');
652→  }
653→
654→  lines.push('-'.repeat(60));
655→  lines.push(`Manage preferences: ${config.baseUrl}/settings`);
656→  lines.push(`Unsubscribe: ${config.unsubscribeUrl}`);
657→  lines.push(`ZeroToShip ${new Date().getFullYear()}`);
658→
659→  return lines.join('\n');
660→}
