function mockResendError(status = 401, message = 'Invalid API key') {
  const resp = {
    ok: false,
    status,
    json: async () => ({
      statusCode: status,
      message,
      name: 'ApiError',
    }),
  };

  // Rate limits and 5xx are retryable in code; keep a stable response for all attempts.
  if (status === 429 || status >= 500) {
    mockFetch.mockResolvedValue(resp);
    return;
