  it('includes hero idea details in HTML', () => {
    const brief = createMockBrief({
      problemStatement: 'Big problem here.',
      keyFeatures: ['automated testing', 'CI/CD integration'],
    });
    const result = buildDailyEmail([brief], 'pro');

